










































import Vue from "vue";

import { skills, SkillsModel } from "@/webservices/spreadsheet.ts";
export default Vue.extend({
  data: () => ({
    skills: [] as SkillsModel[]
  }),
  mounted() {
    skills
      .getSkills()
      .then(res => {
        this.skills = res;
      })
      .catch(err => console.log(err));
  }
});
