























import Vue from "vue";
import { profile } from "@/webservices/spreadsheet";

export default Vue.extend({
  name: "About",
  data: () => ({
    word: ""
  }),
  mounted() {
    profile
      .getProfile()
      .then(result => {
        this.word = result.word;
      })
      .catch(err => {
        console.log(err);
      });
  }
});
