










import Vue from "vue";
export default Vue.extend({
  props: ["name", "credit"],
  data: () => ({
    image: null
  }),
  mounted() {
    this.image = require(`@/assets/${this.name}`);
  },
  methods: {
    openCredit() {
      this.credit != null ? window.open(this.credit) : null;
    }
  }
});
