




























































































import Vue from "vue";
import { projects, ProjectsModel } from "@/webservices/spreadsheet.ts";
export default Vue.extend({
  data: () => ({
    projects: [] as ProjectsModel[],
    image: require("@/assets/project.jpg")
  }),
  methods: {
    openUrl(url: string) {
      window.open(url);
    }
  },
  mounted() {
    projects
      .getProjects()
      .then(res => {
        this.projects = res;
      })
      .catch(err => console.log(err));
  }
});
